const item = $input.first().json;
const blocks = item.content || [];
const text = Array.isArray(blocks)
  ? (blocks.find(b => b.type === 'text') || {}).text || ''
  : String(blocks);
let owner_name = '', confidence = 'low';
try {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) {
    const parsed = JSON.parse(m[0]);
    owner_name = (parsed.owner_name || '').trim();
    confidence = parsed.confidence || 'low';
  }
} catch (_) {}
const pad = n => String(n).padStart(2, '0');
const d = new Date();
const scraped_at = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} `
  + `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
return [{ json: {
  name: item.name || item.business_name || '',
  owner_name,
  email: item.email || '',
  phone: item.phone || '',
  address: item.address || '',
  domain: item.domain || '',
  website: item.website || '',
  category: item.category || '',
  keyword: item.keyword || '',
  search_location: item.search_location || '',
  maps_url: item.maps_url || '',
  scraped_at,
  confidence,
} }];
